import { useState, useEffect } from 'react';
import { conversationSteps } from '../data/script';

export const useConversation = () => {
  const [currentStepIndex, setCurrentStepIndex] = useState(0);
  const [messages, setMessages] = useState([]); // List of chat bubbles on screen
  const [isTyping, setIsTyping] = useState(false);
  const [userData, setUserData] = useState({}); // Stores clinical data

  const currentStep = conversationSteps[currentStepIndex];

  // Effect to "type" out the first message
  useEffect(() => {
    if (messages.length === 0) {
      showNextSystemMessage(0);
    }
  }, []);

  const showNextSystemMessage = (index) => {
    setIsTyping(true);
    setTimeout(() => {
      setMessages(prev => [...prev, { sender: 'bot', text: conversationSteps[index].message }]);
      setIsTyping(false);
    }, 1500); // The "Counselor" thinking delay
  };

  const handleUserAnswer = (answer) => {
    // 1. Add user message to screen
    setMessages(prev => [...prev, { sender: 'user', text: answer }]);
    
    // 2. Save data to our clinical object
    if (currentStep.field) {
      setUserData(prev => ({ ...prev, [currentStep.field]: answer }));
    }

    // 3. Move to next step
    const nextIndex = currentStepIndex + 1;
    if (nextIndex < conversationSteps.length) {
      setCurrentStepIndex(nextIndex);
      showNextSystemMessage(nextIndex);
    }
  };

  return { messages, isTyping, currentStep, handleUserAnswer, userData };
};
